#include <stdio.h>
#include <stdlib.h>

// Definition for singly-linked list node
struct ListNode {
    int val;
    struct ListNode* next;
};

struct ListNode* reverseKGroup(struct ListNode* head, int k) {
    // Creating a dummy node to handle edge cases easily
    struct ListNode* dummy = (struct ListNode*)malloc(sizeof(struct ListNode));
    dummy->next = head;

    // Pointer to keep track of the previous group's tail
    struct ListNode* groupPrev = dummy;

    while (1) {
        // Finding the k-th node from the groupPrev
        struct ListNode* kth = getKthNode(groupPrev, k);
        if (!kth) break;

        // Store the next group's head
        struct ListNode* groupNext = kth->next;

        // Break the chain to reverse current k-group cleanly
        struct ListNode* prev = groupNext;
        struct ListNode* curr = groupPrev->next;

        // Reversing k nodes
        for (int i = 0; i < k; i++) {
            struct ListNode* temp = curr->next;
            curr->next = prev;
            prev = curr;
            curr = temp;
        }

        // Connecting previous group to the reversed group
        struct ListNode* temp = groupPrev->next;
        groupPrev->next = kth;
        groupPrev = temp;
    }

    // Returning the new head
    return dummy->next;
}

// Helper function to find the k-th node from the current node
struct ListNode* getKthNode(struct ListNode* curr, int k) {
    while (curr && k > 0) {
        curr = curr->next;
        k--;
    }
    return curr;
}

